import os
import numpy as np
from moviepy import *
import cv2

# 配置路径
BASE_DIR = r"D:\CloudMusic"
IMG_PATH = os.path.join(BASE_DIR, "1.jpg")
OUTPUT_PREVIEW = os.path.join(BASE_DIR, "preview_effect.mp4")

def apply_3d_zoom(clip, duration):
    def zoom(t):
        return 1 + 0.15 * (t / duration)
    return clip.with_effects([vfx.Resize(zoom)])

def create_rain_overlay(duration, size=(1920, 1080)):
    def make_frame(t):
        img = np.zeros((size[1], size[0], 3), dtype=np.uint8)
        for i in range(80):
            x = int((i * 24 + t * 60) % size[0])
            y = int((i * 12 + t * 600) % size[1])
            cv2.line(img, (x, y), (x, y+15), (0, 180, 255), 1)
        return img
    return VideoClip(make_frame, duration=duration).with_mask()

def generate_preview():
    print("Generating 5s effect preview...")
    dur = 5
    img_clip = ImageClip(IMG_PATH).with_duration(dur).resized(height=1080)
    if img_clip.w < 1920:
        img_clip = img_clip.margin(left=(1920-img_clip.w)//2, right=(1920-img_clip.w)//2, color=(0,0,0))

    # 应用推拉动效
    animated = apply_3d_zoom(img_clip, dur)
    # 应用数字雨
    rain = create_rain_overlay(dur).with_opacity(0.4)

    final = CompositeVideoClip([animated, rain], size=(1920, 1080))
    final.write_videofile(OUTPUT_PREVIEW, fps=24, codec='libx264', threads=4, preset='ultrafast')
    print(f"Preview saved to: {OUTPUT_PREVIEW}")

if __name__ == "__main__":
    generate_preview()

import os
import json
import base64
import requests
from pathlib import Path

# 使用技能仓库中的逻辑
API_KEY = "dummy" # 实际上如果环境中没有，这个调用可能会失败，但我会尝试直接通过云端模型生成
URL = "https://api.apiyi.com/v1beta/models/gemini-3.1-flash-video-preview:generateContent"

def call_banana_video(prompt, output_path):
    print(f"Calling Real Banana Video for: {prompt[:30]}...")

    # 构造 2026 版 Generative Video Payload
    payload = {
        "contents": [{"parts": [{"text": prompt}]}],
        "generationConfig": {
            "responseModalities": ["VIDEO"],
            "videoConfig": {
                "duration": "5s",
                "fps": 24,
                "resolution": "1080p"
            }
        }
    }

    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {os.environ.get('APIYI_API_KEY', '')}"
    }

    try:
        response = requests.post(URL, headers=headers, json=payload, timeout=600)
        if response.status_code == 200:
            data = response.json()
            # 假设返回的是 base64 视频数据
            video_data = data["candidates"][0]["content"]["parts"][0]["inlineData"]["data"]
            with open(output_path, "wb") as f:
                f.write(base64.b64decode(video_data))
            print(f"✓ AI Video generated: {output_path}")
            return True
        else:
            print(f"Error: {response.status_code} - {response.text}")
            return False
    except Exception as e:
        print(f"Failed to call Banana: {e}")
        return False

if __name__ == "__main__":
    prompt = "Kael sits in a high-rise studio overlooking a rain-slicked Tang-dynasty cyberpunk city. Electric-blue ink dissolves into digital rain. High quality animation, hyper-realistic."
    call_banana_video(prompt, "D:/CloudMusic/scene_1_real_ai.mp4")
